mapper.select:
SELECT ser.id, ser.student_id AS studentId, ser.student_no AS studentNo, ser.student_name AS studentName, ser.class_id AS classId, ser.class_name AS className, ser.moral_total_score AS moralTotalScore, ser.moral_weighted_score AS moralWeightedScore, ser.intellectual_total_score AS intellectualTotalScore, ser.intellectual_weighted_score AS intellectualWeightedScore, ser.physical_total_score AS physicalTotalScore, ser.physical_weighted_score AS physicalWeightedScore, ser.aesthetic_total_score AS aestheticTotalScore, ser.aesthetic_weighted_score AS aestheticWeightedScore, ser.labor_total_score AS laborTotalScore, ser.labor_weighted_score AS laborWeightedScore, ser.development_total_score AS developmentTotalScore, ser.development_weighted_score AS developmentWeightedScore, ser.total_score AS totalScore, ser.class_rank AS classRank, ser.class_total AS classTotal, ser.grade_rank AS gradeRank, ser.has_punishment AS hasPunishment, ser.status, ser.calculated_at AS calculatedAt FROM student_evaluation_results ser WHERE ser.evaluation_period_id = #{query.periodId}
AND ser.student_no LIKE CONCAT('%', #{query.studentNo}, '%')
AND ser.student_name LIKE CONCAT('%', #{query.studentName}, '%')
AND ser.class_id = #{query.classId}
AND ser.grade_id = #{query.gradeId}
AND ser.department_id = #{query.departmentId}
AND ser.status = #{query.status}
ORDER BY
ser.total_score DESC ser.class_rank ASC ser.class_name, ser.class_rank ASC

SELECT * FROM student_evaluation_results
WHERE evaluation_period_id = #{periodId} AND class_id = #{classId}
ORDER BY total_score DESC

SELECT * FROM student_evaluation_results
WHERE student_id = #{studentId}
AND evaluation_period_id = #{periodId}
LIMIT 1

SELECT ser.student_no as studentNo, ser.student_name as studentName, ser.class_name as className, ser.moral_total_score as moralScore, ser.intellectual_total_score as intellectualScore, ser.physical_total_score as physicalScore, ser.aesthetic_total_score as aestheticScore, ser.labor_total_score as laborScore, ser.development_total_score as developmentScore, ser.total_score as totalScore, ser.class_rank as classRank, ser.grade_rank as gradeRank, CASE ser.status WHEN 0 THEN '待计算' WHEN 1 THEN '已计算' WHEN 2 THEN '待审核' WHEN 3 THEN '已审核' WHEN 4 THEN '公示中' WHEN 5 THEN '已生效' WHEN 6 THEN '已归档' END as statusText FROM student_evaluation_results ser WHERE ser.evaluation_period_id = #{periodId}
AND ser.class_id = #{classId}
ORDER BY ser.class_name, ser.class_rank
